('xlsx_iowa_crushing_facility_roster', 'xlsx',
INSERT INTO core.kg_node (node_type, node_key, label, properties) VALUES
  ('company', 'cargill', 'Cargill, Inc.', '{"context": "Privately-held global agribusiness conglomerate. Major US oilseed crusher (~25M ton/yr global crush capacity), grain merchandiser, beef/poultry processor, and renewable fuels investor (Diamond Green Diesel JV with Valero).", "type": "oilseed_processor", "category": "private", "primary_us_states_with_operations": ["IA", "IL", "IN", "MN", "NE", "OH", "MO"], "nopa_member": true}'),
  ('company', 'adm', 'Archer-Daniels-Midland Company', '{"context": "Public global agricultural processor (NYSE: ADM). Largest US oilseed crusher by capacity (~30 MMT/yr global). Major ethanol producer, biodiesel/RD via Decatur and other facilities. Renewable fuels JV with Marathon (Spiritwood).", "type": "oilseed_processor", "category": "public", "primary_us_states_with_operations": ["IA", "IL", "IN", "MN", "NE", "OH", "MO"], "nopa_member": true}'),
  ('company', 'agp_ag_processing', 'Ag Processing Inc. (AGP)', '{"context": "Cooperative owned by 150+ regional ag co-ops representing 200,000+ farmer members. 11 US oilseed crushing plants (predominantly soy, all in midwest). Largest US co-op-owned oilseed processor. Operates 4 refineries. Member of NOPA.", "type": "oilseed_processor", "category": "cooperative", "primary_us_states_with_operations": ["IA", "IL", "IN", "MN", "NE", "OH", "MO"], "nopa_member": true}'),
  ('company', 'bunge', 'Bunge Limited', '{"context": "Public global agribusiness (NYSE: BG). ~9 US oilseed crush plants. Renewable fuels JV with Chevron (Bunge-Chevron Ag Renewables). Acquired Viterra in 2024 to become world''s largest oilseed processor by capacity.", "type": "oilseed_processor", "category": "public", "primary_us_states_with_operations": ["IA", "IL", "IN", "MN", "NE", "OH", "MO"], "nopa_member": true}'),
  ('company', 'white_river_nutrition', 'White River Nutrition', '{"context": "Soybean processor with Creston, IA plant. NOPA member as of Sept 2024. Newer entrant in the US oilseed processing complex.", "type": "oilseed_processor", "category": "private", "primary_us_states_with_operations": ["IA"], "nopa_member": true}'),
  ('company', 'shell_rock_soy_processing', 'Shell Rock Soy Processing LLC', '{"context": "Greenfield 110,000 bu/day soybean crushing plant in Shell Rock, IA. Operations began 2024. ~900K tons meal/year output. Co-located biofuel facility planned. Originally announced May 2022 (DTN). NOPA member.", "type": "oilseed_processor", "category": "private", "primary_us_states_with_operations": ["IA"], "nopa_member": true}'),
  ('company', 'platinum_crush', 'Platinum Crush LLC', '{"context": "Greenfield 115,000 bu/day soybean crushing plant in Alta, IA. Operations began 2024. ~875K tons meal, 465M lbs crude oil, 80K tons hulls per year. Built by N Bowdish. NOPA member as of July 2025.", "type": "oilseed_processor", "category": "private", "primary_us_states_with_operations": ["IA"], "nopa_member": true}')
INSERT INTO core.kg_node (node_type, node_key, label, properties) VALUES
  ('market_participant', 'nopa', 'National Oilseed Processors Association (NOPA)', '{"context": "Trade association of US oilseed processors. Publishes monthly NOPA Crush Report (member-reported soybean crush volumes covering ~95% of US soy crush). Founded 1929. Member companies operate the dominant share of US oilseed processing capacity.", "category": "trade_association", "founded": 1929, "key_publication": "NOPA Crush Report (monthly)", "coverage_pct_us_soy_crush": 95, "url": "nopa.org"}')
INSERT INTO core.kg_node (node_type, node_key, label, properties) VALUES
  ('technology', 'solvent_extraction', 'Hexane Solvent Extraction (oilseed crushing)', '{"context": "Industry-standard process for separating oil and meal from oilseeds. Cracked, dehulled seed is flaked, then bathed in hexane solvent which dissolves the oil. Solvent is recovered via desolventizer-toaster. Yields 18-19% oil from soybeans (vs ~14% from expeller pressing). All large US soy crushers use solvent extraction.", "maturity": "commercial", "vs_expeller_oil_yield_pct": "18-19 vs 12-14", "ghg_concern": "hexane VOC emissions regulated under Clean Air Act Title V", "permit_basis": "Title V air permits for VOC emissions"}')
